  <circle cx="580" cy="153" r="8" fill="#4ade80"/>
  <text x="580" y="133" text-anchor="middle" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">Jul 13-14: 0.0282 (high 0.02858)</text>
